    /// Test 3: Kubernetes Operator Controller Lifecycle Management
    #[tokio::test]
    async fn test_operator_lifecycle_management() {
        // Test cluster creation lifecycle
        let mut cluster = BeejsCluster::new(
            "test-cluster".to_string(),
            BeejsClusterSpec {
                version: "v1".to_string(),
                nodes: 3,
                image: "beejs:latest".to_string(),
                resources: ResourceRequirements {
                    cpu: "2".to_string(),
                    memory: "4Gi".to_string(),
                    disk: "20Gi".to_string(),
                },
                security: SecurityConfig {
                    sandbox_enabled: true,
                    rbac_enabled: true,
                    encryption_enabled: true,
                },
                distributed: DistributedConfig {
                    cluster_name: "test-cluster".to_string(),
                    service_discovery: true,
                    load_balancer: true,
                    auto_scaling: true,
                },
            },
        );

        // Test Creating state
        cluster.set_phase(ClusterPhase::Creating);
        assert_eq!(cluster.phase(), ClusterPhase::Creating);

        // Test Running state
        cluster.set_phase(ClusterPhase::Running);
        assert_eq!(cluster.phase(), ClusterPhase::Running);

        // Test Updating state
        cluster.set_phase(ClusterPhase::Updating);
        assert_eq!(cluster.phase(), ClusterPhase::Updating);

        // Test Failed state and recovery
        cluster.set_phase(ClusterPhase::Failed);
        assert_eq!(cluster.phase(), ClusterPhase::Failed);

        cluster.recover();
        assert_eq!(cluster.phase(), ClusterPhase::Running);
    }

    /// Test 4: HPA Auto-scaling Based on CPU Metrics
    #[tokio::test]
    async fn test_hpa_cpu_based_scaling() {
        let mut hpa = HorizontalPodAutoscaler::new(
            "test-workload".to_string(),
            HPAConfig {
                enabled: true,
                min_replicas: 2,
                max_replicas: 20,
                target_cpu_percent: 70,
                target_memory_percent: 80,
            },
        );

        // Simulate low CPU usage - should scale down
        hpa.record_cpu_usage(30.0);
        let scale_action: _ = hpa.calculate_scale_action().await;
        assert!(scale_action.is_some());

        if let Some(action) = scale_action {
            assert!(action.scale_down);
            assert_eq!(action.replicas, 2);
        }

        // Simulate high CPU usage - should scale up
        hpa.record_cpu_usage(85.0);
        let scale_action: _ = hpa.calculate_scale_action().await;
        assert!(scale_action.is_some());

        if let Some(action) = scale_action {
            assert!(action.scale_up);
            assert!(action.replicas > 2);
        }
    }

    /// Test 5: HPA Auto-scaling Based on Memory Metrics
    #[tokio::test]
    async fn test_hpa_memory_based_scaling() {
        let mut hpa = HorizontalPodAutoscaler::new(
            "test-workload".to_string(),
            HPAConfig {
                enabled: true,
                min_replicas: 2,
                max_replicas: 20,
                target_cpu_percent: 70,
                target_memory_percent: 80,
            },
        );

        // Simulate high memory usage - should scale up
        hpa.record_memory_usage(90.0);
        let scale_action: _ = hpa.calculate_scale_action().await;
        assert!(scale_action.is_some());

        if let Some(action) = scale_action {
            assert!(action.scale_up);
            assert!(action.replicas >= 3);
        }

        // Simulate normal memory usage - should maintain
        hpa.record_memory_usage(60.0);
        let scale_action: _ = hpa.calculate_scale_action().await;
        assert!(scale_action.is_none()); // No scaling needed
    }

    /// Test 6: Container Security Scanning
    #[tokio::test]
    async fn test_container_security_scan() {
        let scanner: _ = ContainerSecurityScanner::new();

        let image_info: _ = ContainerImage {
            name: "beejs:latest".to_string(),
            digest: "sha256:1234567890abcdef".to_string(),
            layers: vec![
                ImageLayer {
                    id: "layer1".to_string(),
                    size: 100 * 1024 * 1024, // 100MB
                    vulnerabilities: vec![
                        Vulnerability {
                            id: "CVE-2023-1234".to_string(),
                            severity: "HIGH".to_string(),
                            description: "Security vulnerability in base image".to_string(),
                        },
                    ],
                },
                ImageLayer {
                    id: "layer2".to_string(),
                    size: 50 * 1024 * 1024, // 50MB
                    vulnerabilities: vec![],
                },
            ],
        };

        let scan_result: _ = scanner.scan_image(&image_info).await;
        assert!(scan_result.is_ok());

        let report: _ = scan_result.unwrap();
        assert_eq!(report.total_layers, 2);
        assert_eq!(report.vulnerable_layers, 1);
        assert_eq!(report.total_vulnerabilities, 1);
        assert_eq!(report.severity_summary.get("HIGH"), Some(&1));
    }

    /// Test 7: Multi-stage Docker Build Optimization
    #[tokio::test]
    async fn test_multi_stage_docker_build() {
        let dockerfile: _ = r#"
FROM rust:1.70 as builder
WORKDIR /app
COPY . .
RUN cargo build --release

FROM debian:bookworm-slim
COPY --from=builder /app/target/release/beejs /usr/local/bin/
ENTRYPOINT ["beejs"]
"#;

        let optimizer: _ = DockerBuildOptimizer::new(dockerfile.to_string());
        let optimized: _ = optimizer.optimize_multi_stage_build().await;
        assert!(optimized.is_ok());

        let result: _ = optimized.unwrap();
        assert!(result.contains("FROM rust:1.70 as builder"));
        assert!(result.contains("FROM debian:bookworm-slim"));
        assert!(result.contains("COPY --from=builder"));
        assert!(result.contains("ENTRYPOINT"));
    }

