// Additional supporting types
struct BeejsCluster {
    name: String,
    spec: BeejsClusterSpec,
    phase: ClusterPhase,
}

impl BeejsCluster {
    fn new(name: String, spec: BeejsClusterSpec) -> Self {
        Self {
            name,
            spec,
            phase: ClusterPhase::Pending,
        }
    }

    fn spec(&self) -> &BeejsClusterSpec {
        &self.spec
    }

    fn phase(&self) -> ClusterPhase {
        self.phase.clone()
    }

    fn set_phase(&mut self, phase: ClusterPhase) {
        self.phase = phase;
    }

    fn recover(&mut self) {
        self.phase = ClusterPhase::Running;
    }
}

